def sum_list(nums):
    total = 0
    for x in nums:
        total += x
    return total

def max_of(nums):
    m = nums[0]
    for x in nums:
        if x > m:
            m = x
    return m

def factorial(n):
    result = 1
    for i in range(1, n + 1):
        result *= i
    return result

def unique(nums):
    out = []
    for x in nums:
        if x not in out:
            out.append(x)
    return out

def fib(n):
    a, b = 0, 1
    for _ in range(n):
        a, b = b, a + b
    return a

def word_count(s):
    counts = {}
    for w in s.split():
        counts[w] = counts.get(w, 0) + 1
    return counts

def reverse_list(nums):
    out = []
    for x in nums:
        out.insert(0, x)
    return out

def fizzbuzz(n):
    out = []
    for i in range(1, n + 1):
        if i % 15 == 0:
            out.append('FizzBuzz')
        elif i % 3 == 0:
            out.append('Fizz')
        elif i % 5 == 0:
            out.append('Buzz')
        else:
            out.append(str(i))
    return out

def two_sum(nums, target):
    seen = {}
    for i, x in enumerate(nums):
        if target - x in seen:
            return [seen[target - x], i]
        seen[x] = i

def gcd(a, b):
    while b:
        a, b = b, a % b
    return a

def flatten(nested):
    out = []
    for sub in nested:
        for x in sub:
            out.append(x)
    return out

def most_common_char(s):
    counts = {}
    for c in s:
        counts[c] = counts.get(c, 0) + 1
    best = None
    for c in sorted(counts):
        if best is None or counts[c] > counts[best]:
            best = c
    return best

def second_largest(nums):
    u = sorted(set(nums))
    return u[-2]

def rotate(nums, k):
    if not nums:
        return []
    k = k % len(nums)
    return nums[-k:] + nums[:-k]

def group_by_parity(nums):
    out = {"even": [], "odd": []}
    for x in nums:
        if x % 2 == 0:
            out["even"].append(x)
        else:
            out["odd"].append(x)
    return out

def max_value_key(d):
    best = None
    for k in sorted(d):
        if best is None or d[k] > d[best]:
            best = k
    return best

def dict_from_pairs(pairs):
    out = {}
    for k, v in pairs:
        out[k] = v
    return out

def is_prime(n):
    if n < 2:
        return False
    i = 2
    while i * i <= n:
        if n % i == 0:
            return False
        i += 1
    return True

def sum_digits(n):
    total = 0
    while n > 0:
        total += n % 10
        n //= 10
    return total

def binary_search(nums, target):
    lo, hi = 0, len(nums) - 1
    while lo <= hi:
        mid = (lo + hi) // 2
        if nums[mid] == target:
            return mid
        if nums[mid] < target:
            lo = mid + 1
        else:
            hi = mid - 1
    return -1

def bubble_sort(nums):
    arr = list(nums)
    n = len(arr)
    for i in range(n):
        for j in range(n - 1 - i):
            if arr[j] > arr[j + 1]:
                arr[j], arr[j + 1] = arr[j + 1], arr[j]
    return arr

def max_subarray(nums):
    best = cur = nums[0]
    for x in nums[1:]:
        cur = max(x, cur + x)
        best = max(best, cur)
    return best

def digital_root(n):
    while n >= 10:
        s = 0
        while n > 0:
            s += n % 10
            n //= 10
        n = s
    return n

def status_bucket(code):
    if code < 200:
        return "informational"
    if code < 300:
        return "success"
    if code < 400:
        return "redirect"
    if code < 500:
        return "client_error"
    return "server_error"

def parse_query(qs):
    out = {}
    if not qs:
        return out
    for part in qs.split("&"):
        k, _, v = part.partition("=")
        out[k] = v
    return out

def normalize_path(path):
    parts = [p for p in path.split("/") if p]
    if not parts:
        return "/"
    return "/" + "/".join(parts)
